package com.mobiledev.mindaguard.backend

import android.net.Uri
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.google.firebase.FirebaseApp
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.storage.FirebaseStorage
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await

sealed class EditProfileUiState {
    object Idle : EditProfileUiState()
    object Loading : EditProfileUiState()
    object Success : EditProfileUiState()
    data class Error(val message: String) : EditProfileUiState()
}

@Suppress("unused")
class EditProfileViewModel : ViewModel() {

    private val auth = FirebaseAuth.getInstance()
    private val db = FirebaseFirestore.getInstance(FirebaseApp.getInstance(), "default")
    private val storage = FirebaseStorage.getInstance()

    private val _uiState = MutableStateFlow<EditProfileUiState>(EditProfileUiState.Idle)
    @Suppress("unused")
    val uiState: StateFlow<EditProfileUiState> = _uiState

    private val _photoUrl = MutableStateFlow<String?>(null)
    @Suppress("unused")
    val photoUrl: StateFlow<String?> = _photoUrl

    @Suppress("unused")
    fun loadCurrentPhoto() {
        val uid = auth.currentUser?.uid ?: return
        viewModelScope.launch {
            try {
                val snapshot = db.collection("users").document(uid).get().await()
                _photoUrl.value = snapshot.getString("photoUrl")
            } catch (_: Exception) { }
        }
    }

    @Suppress("unused")
    fun saveProfile(
        firstName: String,
        lastName: String,
        mobile: String,
        district: String,
        barangay: String,
        pickedImageUri: Uri?,
        onDone: () -> Unit
    ) {
        val user = auth.currentUser
        if (user == null) {
            _uiState.value = EditProfileUiState.Error("Not logged in")
            return
        }

        viewModelScope.launch {
            _uiState.value = EditProfileUiState.Loading
            try {
                // Upload profile picture if a new one was picked
                val uploadedUrl: String? = if (pickedImageUri != null) {
                    val ref = storage.reference
                        .child("profile_pictures/${user.uid}.jpg")
                    ref.putFile(pickedImageUri).await()
                    ref.downloadUrl.await().toString()
                } else null

                // Build update map
                val updates = mutableMapOf<String, Any>(
                    "firstName" to firstName.trim(),
                    "lastName"  to lastName.trim(),
                    "mobile"    to mobile.trim(),
                    "district"  to district,
                    "barangay"  to barangay
                )
                if (uploadedUrl != null) {
                    updates["photoUrl"] = uploadedUrl
                    _photoUrl.value = uploadedUrl
                }

                db.collection("users").document(user.uid)
                    .update(updates)
                    .await()

                _uiState.value = EditProfileUiState.Success
                onDone()
            } catch (e: Exception) {
                _uiState.value = EditProfileUiState.Error(e.message ?: "Failed to save profile")
            }
        }
    }

    @Suppress("unused")
    fun resetState() {
        _uiState.value = EditProfileUiState.Idle
    }
}

package com.mobiledev.mindaguard.backend

import android.net.Uri
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.google.firebase.FirebaseApp
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.storage.StorageException
import com.google.firebase.storage.FirebaseStorage
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await

sealed class EditProfileUiState {
    object Idle : EditProfileUiState()
    object Loading : EditProfileUiState()
    object Success : EditProfileUiState()
    data class Error(val message: String) : EditProfileUiState()
}

@Suppress("unused")
class EditProfileViewModel : ViewModel() {

    private val auth = FirebaseAuth.getInstance()
    private val db = FirebaseFirestore.getInstance(FirebaseApp.getInstance(), "default")
    private val storage = FirebaseStorage.getInstance()
    private val profilesRepository = ProfilesRepository(auth = auth, db = db)

    private val _uiState = MutableStateFlow<EditProfileUiState>(EditProfileUiState.Idle)
    @Suppress("unused")
    val uiState: StateFlow<EditProfileUiState> = _uiState

    private val _photoUrl = MutableStateFlow<String?>(null)
    @Suppress("unused")
    val photoUrl: StateFlow<String?> = _photoUrl

    @Suppress("unused")
    fun loadCurrentPhoto() {
        val uid = auth.currentUser?.uid ?: return
        viewModelScope.launch {
            try {
                // Prefer active profile photo
                profilesRepository.ensureDefaultProfile()
                val profile = profilesRepository.getActiveProfile()
                _photoUrl.value = profile.photoUrl
            } catch (_: Exception) { }
        }
    }

    @Suppress("unused")
    fun saveProfile(
        firstName: String,
        lastName: String,
        mobile: String,
        district: String,
        barangay: String,
        pickedImageUri: Uri?,
        onDone: () -> Unit
    ) {
        val user = auth.currentUser
        if (user == null) {
            _uiState.value = EditProfileUiState.Error("Not logged in")
            return
        }

        viewModelScope.launch {
            _uiState.value = EditProfileUiState.Loading
            try {
                // Ensure an active profile exists (lazy migration from legacy /users/{uid})
                val activeProfileId = profilesRepository.ensureDefaultProfile()

                // Upload photo to a per-profile path
                val uploadedUrl: String? = if (pickedImageUri != null) {
                    try {
                        val ref = storage.reference
                            .child("profile_pictures/${user.uid}/${activeProfileId}.jpg")
                        ref.putFile(pickedImageUri).await()
                        ref.downloadUrl.await().toString()
                    } catch (e: Exception) {
                        val msg = when (e) {
                            is StorageException -> e.message ?: "Storage upload failed"
                            else -> e.message ?: "Storage upload failed"
                        }
                        throw IllegalStateException("Photo upload failed: $msg", e)
                    }
                } else null

                profilesRepository.updateActiveProfile(
                    firstName = firstName,
                    lastName = lastName,
                    mobile = mobile,
                    district = district,
                    barangay = barangay,
                    photoUrl = uploadedUrl
                )

                if (!uploadedUrl.isNullOrBlank()) {
                    _photoUrl.value = uploadedUrl
                }


                _uiState.value = EditProfileUiState.Success
                onDone()
            } catch (e: Exception) {
                _uiState.value = EditProfileUiState.Error(e.message ?: "Failed to save profile")
            }
        }
    }

    @Suppress("unused")
    fun resetState() {
        _uiState.value = EditProfileUiState.Idle
    }
}

rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // ── Helper: check admin via Auth custom claim ─────────────────────────────
    // Set the claim with Firebase Admin SDK:
    //   admin.auth().setCustomUserClaims(uid, { role: 'admin' })
    function isAdmin() {
      return request.auth != null
          && request.auth.token.role == 'admin';
    }

    // ── Users collection ──────────────────────────────────────────────────────
    // Users can only read/write their own document.
    match /users/{uid} {
      allow read, write: if request.auth != null && request.auth.uid == uid;
    }

    // ── Community Alerts ──────────────────────────────────────────────────────
    // EVERYONE (including guests) can READ community alerts so that
    // the feed is visible to all users regardless of sign-in status.
    // Any authenticated user can CREATE an alert (submittedBy must match UID).
    // Only admins can UPDATE or DELETE.
    match /community_alerts/{alertId} {
      allow read: if true;   // public — visible to all users & guests

      allow create: if request.auth != null
                    && request.resource.data.submittedBy == request.auth.uid;

      allow update: if isAdmin();

      allow delete: if isAdmin();
    }
  }
}

rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // ── Helper: check admin via Auth custom claim ─────────────────────────────
    // Set the claim with Firebase Admin SDK:
    //   admin.auth().setCustomUserClaims(uid, { role: 'admin' })
    function isAdmin() {
      return request.auth != null
          && request.auth.token.role == 'admin';
    }

    // ── Users collection ──────────────────────────────────────────────────────
    // Users can only read/write their own document.
    match /users/{uid} {
      allow read, write: if request.auth != null && request.auth.uid == uid;

      // Subcollection: profiles (multi-profile support)
      match /profiles/{profileId} {
        allow read, write: if request.auth != null && request.auth.uid == uid;
      }
    }

    // ── Community Alerts ──────────────────────────────────────────────────────
    // EVERYONE (including guests) can READ community alerts so that
    // the feed is visible to all users regardless of sign-in status.
    // Any authenticated user can CREATE an alert (submittedBy must match UID).
    // Only admins can UPDATE or DELETE.
    match /community_alerts/{alertId} {
      allow read: if true;   // public — visible to all users & guests

      allow create: if request.auth != null
                    && request.resource.data.submittedBy == request.auth.uid;

      allow update: if isAdmin();

      allow delete: if isAdmin();
    }
  }
}

rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {

    function isSignedIn() {
      return request.auth != null;
    }

    // Users can read/write only their own profile pictures
    // Path used by app: profile_pictures/{uid}/{profileId}.jpg
    match /profile_pictures/{uid}/{allPaths=**} {
      allow read, write: if isSignedIn() && request.auth.uid == uid;
    }

    // Default deny
    match /{allPaths=**} {
      allow read, write: if false;
    }
  }
}
